9	// TestEscalatableStatusesMatchAgentVocab guards against drift between
10	// agent's ExecuteBeadStatus* constants and escalation.EscalatableStatuses.
11	// If you rename a status in execute_bead_status.go, update both places.
12	func TestEscalatableStatusesMatchAgentVocab(t *testing.T) {
13		expected := map[string]bool{
14			ExecuteBeadStatusExecutionFailed:            true,
15			ExecuteBeadStatusPostRunCheckFailed:         true,
16			ExecuteBeadStatusLandConflict:               true,
17			ExecuteBeadStatusStructuralValidationFailed: true,
18		}
19		for status := range expected {
20			if !escalation.EscalatableStatuses[status] {
21				t.Errorf("agent escalatable status %q is not in escalation.EscalatableStatuses", status)
22			}
23		}
24		for status := range escalation.EscalatableStatuses {
25			if !expected[status] {
26				t.Errorf("escalation.EscalatableStatuses has %q not in agent's expected set", status)
27			}
28		}
29		// SuccessStatus alignment
30		if escalation.SuccessStatus != ExecuteBeadStatusSuccess {
31			t.Errorf("escalation.SuccessStatus = %q, want %q (ExecuteBeadStatusSuccess)",
32				escalation.SuccessStatus, ExecuteBeadStatusSuccess)
33		}
34	}
